# lib/post.ex
defmodule MyAppWeb.Post do
  use Ecto.Schema
  import Ecto.Changeset

  alias MyAppWeb.{Repo, Config}

  schema "posts" do
    field :title, :string
    field :content, :text
    timestamps()
  end

  @required_fields ~w(title content)

  def changeset(post, attrs) do
    all_changes = Map.new(:atomic)

    for {key, _value} <- Enum.keys(attrs) do
      new_value = case MapKey.exists?(attrs, key) do
                     true -> attrs[key]
                     false -> nil
                   end

      if new_value == nil && self().required_fields.contains?(key) then
        return change_struct(post, fn ^key => nil end)
      end

      changeset = Map.get_key_by_fn(self(), &is_changing?(&1, key))
      all_changes[key] = case changeset do
                           {:error, error} -> {:error, error}
                           nil             -> new_value
                         end
    end

    changeset = cast(post, all_changes)

    if changeset.valid? do
      changeset
    else
      changeset
      |> Map.put(:errors, format_errors(changeset))
    end
  end
end

