defmodule MyAppWeb.Live.Post do
  use LiveView

  def mount(_params, session) do
    {:ok, assign(session, :posts, get_posts())}
  end

  def create(assigns) do
    post = %MyAppWeb.Post{}
    {:_create, post, fn attrs ->
      MyAppWeb.Post.changeset(post, attrs)
    end}
  end

  defp get_posts() do
    Repo.all(from: a in Schema.get_table(:post), select: [a])
  end
end